plist.dict:
CFBundlePackageType
APPL
CFBundleName
DKST Terminal AI
CFBundleExecutable
DKST Terminal AI
CFBundleIdentifier
com.dinkisstyle.terminalai
CFBundleVersion
{{.Info.ProductVersion}}
CFBundleGetInfoString
{{.Info.Comments}}
CFBundleShortVersionString
{{.Info.ProductVersion}}
CFBundleIconFile
iconfile
LSMinimumSystemVersion
10.13.0
NSHighResolutionCapable
true
NSHumanReadableCopyright
{{.Info.Copyright}}
{{if .Info.FileAssociations}}
CFBundleDocumentTypes

  {{range .Info.FileAssociations}}

    CFBundleTypeExtensions

      {{.Ext}}

    CFBundleTypeName
    {{.Name}}
    CFBundleTypeRole
    {{.Role}}
    CFBundleTypeIconFile
    {{.IconName}}

  {{end}}

{{end}}
{{if .Info.Protocols}}
CFBundleURLTypes

  {{range .Info.Protocols}}

        CFBundleURLName
        com.wails.{{.Scheme}}
        CFBundleURLSchemes

            {{.Scheme}}

        CFBundleTypeRole
        {{.Role}}

  {{end}}

{{end}}
NSHighResolutionCapable

NSAppleEventsUsageDescription
This app requires Apple Events access to coordinate terminal-driven tasks on your Mac.
NSDesktopFolderUsageDescription
This app requires access to your Desktop folder to read, create, and manage files requested through terminal tasks.
NSDocumentsFolderUsageDescription
This app requires access to your Documents folder to read, create, and manage files requested through terminal tasks.
NSDownloadsFolderUsageDescription
This app requires access to your Downloads folder to read, create, and manage files requested through terminal tasks.
NSRemovableVolumesUsageDescription
This app requires access to external volumes to read, create, and manage files requested through terminal tasks.
NSNetworkVolumesUsageDescription
This app requires access to network volumes to read, create, and manage files requested through terminal tasks.
